#include <iostream>
using namespace std;

class Base {
public:
 Base() { cout << "Base Constructor\n"; }
 ~Base() { cout << "Base Destructor\n"; }
};

class Derived : public Base {
public:
 Derived() { cout << "Derived Constructor\n"; }
 ~Derived() { cout << "Derived Destructor\n"; }
};

int main() {
 Derived obj;
 // Output:
 // Base Constructor
 // Derived Constructor
 // Derived Destructor
 // Base Destructor
 return 0;
}

#include <iostream>
using namespace std;

class Animal {
public:
 Animal() { cout << "Animal Constructor\n"; }
 virtual ~Animal() { cout << "Animal Destructor\n"; } // Virtual!
};

class Dog : public Animal {
public:
 Dog() { cout << "Dog Constructor\n"; }
 ~Dog() { cout << "Dog Destructor\n"; }
};

int main() {
 Animal* ptr = new Dog();
 cout << "---\n";
 delete ptr;
 /* Output:
 Animal Constructor
 Dog Constructor
 ---
 Dog Destructor
 Animal Destructor
 */
 return 0;
}

#include <iostream>
using namespace std;

class Sample {
 int id;
public:
 Sample(int i) : id(i) { 
 cout << "Constructor: " << id << endl; 
 }
 Sample(const Sample& s) : id(s.id) { 
 cout << "Copy Constructor: " << id << endl; 
 }
 ~Sample() { 
 cout << "Destructor: " << id << endl; 
 }
};

void funcByValue(Sample s) { // Scenario 1: pass by value
 cout << "Inside funcByValue\n";
}

Sample funcReturn() { // Scenario 2: return by value
 Sample s(2);
 return s;
}

int main() {
 // Scenario 1: Passing to function
 cout << "=== Pass by value ===\n";
 Sample s1(1);
 funcByValue(s1);

 // Scenario 2: Returning from function
 cout << "\n=== Return by value ===\n";
 Sample s3 = funcReturn();

 // Scenario 3: Explicit initialization
 cout << "\n=== Explicit init ===\n";
 Sample s4 = s1;

 cout << "\n=== End of main ===\n";
 return 0;
}

#include <iostream>
using namespace std;

class Tracker {
 string name;
 static int count;
public:
 Tracker(string n) : name(n) {
 count++;
 cout << "Constructed: " << name << " (#" << count << ")\n";
 }
 ~Tracker() {
 cout << "Destructed: " << name << "\n";
 }
};

int Tracker::count = 0;

Tracker globalObj("Global"); // Before main()

void testFunction() {
 static Tracker staticLocal("StaticLocal");
 Tracker local("Local");
}

int main() {
 cout << "=== main starts ===\n";
 testFunction();
 cout << "=== testFunction called again ===\n";
 testFunction();
 cout << "=== main ends ===\n";
 return 0;
}

#include <iostream>
using namespace std;

class MemberA {
public:
 MemberA() { cout << "MemberA constructed\n"; }
 ~MemberA() { cout << "MemberA destroyed\n"; }
};

class MemberB {
public:
 MemberB() { cout << "MemberB constructed\n"; }
 ~MemberB() { cout << "MemberB destroyed\n"; }
};

class Container {
 MemberB b; // Declared second
 MemberA a; // Declared first
public:
 Container() { cout << "Container constructor\n"; }
 ~Container() { cout << "Container destructor\n"; }
};

int main() {
 Container obj;
 /* Output:
 MemberA constructed (because declared first!)
 MemberB constructed
 Container constructor
 Container destructor
 MemberB destroyed
 MemberA destroyed
 */
 return 0;
}
